import React from 'react';

// FIX: Removed circular self-import of UserProfile to resolve the 'Import declaration conflicts with local declaration' error.

export enum TransactionType {
  ADD = 'ADD',
  REMOVE = 'REMOVE',
  WITHDRAW = 'WITHDRAW',
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  date: string;
  description?: string;
}

export interface PriceAlert {
  id: string;
  type: 'above' | 'below';
  targetPrice: number;
  status: 'active' | 'triggered';
  createdAt: string;
}

export interface Asset {
  id: string;
  name: string;
  ticker: string;
  balance: number;
  price: number;
  logoUrl?: string;
  transactions: Transaction[];
  priceAlerts: PriceAlert[];
}

export interface UserProfile {
  fullName: string;
  email: string;
  bio: string;
  profilePicture: string | null;
}

export type Theme = 'light' | 'dark';

export interface Receipt {
  transactionId: string;
  date: string;
  status: 'Payment Successful' | 'Completed' | 'Failed';
  userProfile: UserProfile;
  amountGBP: number;
  amountLocal: number;
  currency: string;
  exchangeRate: number;
  bankName: string;
  accountHolderName: string;
  accountNumber: string;
}

export interface Notification {
  id: string;
  type: 'investors' | 'investment' | 'withdrawal' | 'price_alert' | 'new_member';
  icon: React.ElementType;
  title: string;
  message: string;
  timestamp: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Asset, TransactionType, UserProfile, Notification, Receipt, PriceAlert } from './types';
import LandingPage from './components/LandingPage';
import LoginScreen from './components/LoginScreen';
import ManageBalanceModal from './components/ManageBalanceModal';
import TransactionHistoryModal from './components/TransactionHistoryModal';
import { initialAssets as newInitialAssets, initialProfile as newInitialProfile } from './mockData';
import LiveChartModal from './components/LiveChartModal';
import PriceAlertModal from './components/PriceAlertModal';
import { BanknotesIcon, BellAlertIcon, ChartBarIcon, UserPlusIcon } from './components/Icons';
import NotificationPopup from './components/NotificationPopup';
import WithdrawModal from './components/WithdrawModal';
import WithdrawalReceipt from './components/WithdrawalReceipt';
import ProfileModal from './components/ProfileModal';
import MobileDashboard from './components/MobileDashboard';

type ModalState = {
  type: 'manageBalance' | 'history' | 'chart' | 'alert' | null;
  asset: Asset | null;
};

// --- User Data Management ---
const USERS_DB_KEY = 'invest_empowerment_users';
const ACTIVE_USER_KEY = 'invest_empowerment_active_user';

const MOCK_INVESTORS = [
    { name: 'Mary T.', location: 'Port Moresby, Papua New Guinea' },
    { name: 'Ratu S.', location: 'Suva, Fiji' },
    { name: 'David K.', location: 'Lae, Papua New Guinea' },
    { name: 'Grace V.', location: 'Honiara, Solomon Islands' },
    { name: 'John P.', location: 'Mount Hagen, Papua New Guinea' },
    { name: 'Sarah L.', location: 'Goroka, Papua New Guinea' },
    { name: 'Tui F.', location: 'Apia, Samoa' },
    { name: 'Lina M.', location: 'Nukuʻalofa, Tonga' },
    { name: 'Ben G.', location: 'Port Vila, Vanuatu' },
    { name: 'Anna P.', location: 'Madang, Papua New Guinea' },
    { name: 'Samuel J.', location: 'Lautoka, Fiji' },
    { name: 'Jessica W.', location: 'Auki, Solomon Islands' },
];

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [getStarted, setGetStarted] = useState(false);
  const [loginError, setLoginError] = useState('');

  // State for the currently logged-in user
  const [activeUserEmail, setActiveUserEmail] = useState<string | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [investmentStartTime, setInvestmentStartTime] = useState<number | null>(null);

  const [modal, setModal] = useState<ModalState>({ type: null, asset: null });
  const [isWithdrawModalOpen, setIsWithdrawModalOpen] = useState(false);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [currentView, setCurrentView] = useState<'dashboard' | 'receipt'>('dashboard');
  const [activeReceipt, setActiveReceipt] = useState<Receipt | null>(null);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return 'dark';
    }
    return 'light';
  });

  useEffect(() => {
    // Auto-login check on initial load
    const loggedInUserEmail = localStorage.getItem(ACTIVE_USER_KEY);
    if (loggedInUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const userData = users[loggedInUserEmail];
      if (userData) {
        setActiveUserEmail(loggedInUserEmail);
        setAssets(userData.assets);
        setUserProfile(userData.profile);
        setInvestmentStartTime(userData.investmentStartTime);
        setIsLoggedIn(true);
      }
    }
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const saveUserData = (email: string, data: any) => {
    const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
    users[email] = data;
    localStorage.setItem(USERS_DB_KEY, JSON.stringify(users));
  };

  const addNotification = (notification: Omit<Notification, 'id' | 'timestamp'>) => {
    const newNotification: Notification = {
      ...notification,
      id: Date.now().toString() + Math.random(),
      timestamp: new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
    };
    setNotifications(prev => [newNotification, ...prev]);
  };

  const removeNotification = (id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  };

  useEffect(() => {
    if (!isLoggedIn) return;
    const activityInterval = setInterval(() => {
      if (notifications.length >= 5) return;
      const randomInvestor = MOCK_INVESTORS[Math.floor(Math.random() * MOCK_INVESTORS.length)];
      const randomAction = Math.random();
      let notificationData: Omit<Notification, 'id' | 'timestamp'>;
      if (randomAction < 0.5) {
        const amount = Math.floor(Math.random() * (5000 - 100 + 1) + 100);
        notificationData = { type: 'investment', icon: ChartBarIcon, title: 'New Investment', message: `${randomInvestor.name} from ${randomInvestor.location} has invested $${amount.toLocaleString()}.` };
      } else if (randomAction < 0.8) {
        const amount = Math.floor(Math.random() * (2000 - 200 + 1) + 200);
        notificationData = { type: 'withdrawal', icon: BanknotesIcon, title: 'Profit Withdrawal', message: `${randomInvestor.name} from ${randomInvestor.location} withdrew $${amount.toLocaleString()}.` };
      } else {
        notificationData = { type: 'new_member', icon: UserPlusIcon, title: 'Welcome!', message: `${randomInvestor.name} from ${randomInvestor.location} has just joined!` };
      }
      addNotification(notificationData);
    }, 4000);
    return () => clearInterval(activityInterval);
  }, [isLoggedIn, notifications]);

  const handleLogin = (email: string, password: string): boolean => {
    setLoginError('');
    const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
    const userData = users[email.toLowerCase()];

    if (userData && userData.password === password) {
      setActiveUserEmail(email.toLowerCase());
      setAssets(userData.assets);
      setUserProfile(userData.profile);
      setInvestmentStartTime(userData.investmentStartTime);
      setIsLoggedIn(true);
      localStorage.setItem(ACTIVE_USER_KEY, email.toLowerCase());
      addNotification({ type: 'new_member', icon: UserPlusIcon, title: 'Welcome back', message: 'You are now signed in to your dashboard.' });
      return true;
    }
    setLoginError('Invalid email or password.');
    return false;
  };

  const handleSignup = (email: string, password: string): boolean => {
    setLoginError('');
    const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
    const lowerCaseEmail = email.toLowerCase();

    if (users[lowerCaseEmail]) {
      setLoginError('An account with this email already exists.');
      return false;
    }

    const startTime = Date.now();
    const newUserProfile = { ...newInitialProfile, email: lowerCaseEmail, fullName: 'New Investor' };
    const newUserData = {
      password,
      profile: newUserProfile,
      assets: newInitialAssets,
      investmentStartTime: startTime,
    };

    saveUserData(lowerCaseEmail, newUserData);

    setActiveUserEmail(lowerCaseEmail);
    setAssets(newInitialAssets);
    setUserProfile(newUserProfile);
    setInvestmentStartTime(startTime);
    setIsLoggedIn(true);
    localStorage.setItem(ACTIVE_USER_KEY, lowerCaseEmail);
    addNotification({ type: 'new_member', icon: UserPlusIcon, title: 'Account Created!', message: 'Welcome to INVEST EMPOWERMENT!' });
    return true;
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setGetStarted(false);
    setActiveUserEmail(null);
    setAssets([]);
    setUserProfile(null);
    localStorage.removeItem(ACTIVE_USER_KEY);
  };

  const handleUpdateBalance = (assetId: string, amount: number, type: TransactionType, description?: string) => {
    const updatedAssets = assets.map(asset => {
      if (asset.id === assetId) {
        const newBalance = type === TransactionType.ADD ? asset.balance + amount : asset.balance - amount;
        const newTransaction = { id: `tx-${Date.now()}`, type, amount, date: new Date().toISOString(), description };
        addNotification({ type: 'investment', icon: ChartBarIcon, title: `Balance Updated for ${asset.ticker}`, message: `Successfully ${type === TransactionType.ADD ? 'added' : 'removed'} ${amount} ${asset.ticker}.` });
        return { ...asset, balance: newBalance, transactions: [...asset.transactions, newTransaction] };
      }
      return asset;
    });
    setAssets(updatedAssets);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }
  };

  const handleWithdraw = (details: { amount: number; convertedAmount: number; currency: string; rate: number; bankName: string; accountHolderName: string; accountNumber: string; }) => {
    if (!userProfile) return;
    const newReceipt: Receipt = {
      transactionId: `WD-${Date.now()}`, 
      date: new Date().toISOString(), 
      status: 'Payment Successful', 
      userProfile,
      amountGBP: details.amount, 
      amountLocal: details.convertedAmount, 
      currency: details.currency,
      exchangeRate: details.rate, 
      bankName: details.bankName, 
      accountHolderName: details.accountHolderName,
      accountNumber: details.accountNumber,
    };

    let remainingWithdrawal = details.amount;
    const updatedAssets = assets.map(asset => {
      const assetValue = asset.balance * asset.price;
      if (remainingWithdrawal > 0 && assetValue > 0) {
        const withdrawalFromAsset = Math.min(remainingWithdrawal, assetValue);
        const balanceToRemove = withdrawalFromAsset / asset.price;
        remainingWithdrawal -= withdrawalFromAsset;
        return { ...asset, balance: asset.balance - balanceToRemove };
      }
      return asset;
    }).filter(asset => asset.balance > 0.00001);

    setAssets(updatedAssets);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }

    addNotification({ type: 'withdrawal', icon: BanknotesIcon, title: 'Withdrawal Successful', message: `Your withdrawal of ${details.amount.toLocaleString('en-GB', {style: 'currency', currency: 'GBP'})} has been processed.` });
    setActiveReceipt(newReceipt);
    setCurrentView('receipt');
    setIsWithdrawModalOpen(false);
  };

  const handleAddAlert = (assetId: string, alert: Omit<PriceAlert, 'id' | 'status' | 'createdAt'>) => {
    const updatedAssets = assets.map(asset => {
      if (asset.id === assetId) {
        const newAlert: PriceAlert = { ...alert, id: `alert-${Date.now()}`, status: 'active' as const, createdAt: new Date().toISOString() };
        addNotification({ type: 'price_alert', icon: BellAlertIcon, title: 'Price Alert Set', message: `Alert for ${asset.ticker} when price is ${alert.type} ${alert.targetPrice.toLocaleString('en-GB', {style: 'currency', currency: 'GBP'})}.` });
        return { ...asset, priceAlerts: [...asset.priceAlerts, newAlert] };
      }
      return asset;
    });
    setAssets(updatedAssets);
     if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }
  };

  const handleDeleteAlert = (assetId: string, alertId: string) => {
    const updatedAssets = assets.map(asset => {
      if (asset.id === assetId) {
        return { ...asset, priceAlerts: asset.priceAlerts.filter(a => a.id !== alertId) };
      }
      return asset;
    });
    setAssets(updatedAssets);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }
  };

  const handleSaveProfile = (updatedProfile: UserProfile) => {
    setUserProfile(updatedProfile);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, profile: updatedProfile });
    }
    addNotification({ type: 'new_member', icon: UserPlusIcon, title: 'Profile Updated', message: 'Your profile information has been saved successfully.' });
  };

  const stockAssets = useMemo(() => assets.filter(asset => asset.ticker !== 'BTC' && asset.ticker !== 'GBP'), [assets]);

  if (!isLoggedIn || !userProfile) {
    return getStarted 
      ? <LoginScreen onLogin={handleLogin} onSignup={handleSignup} error={loginError} />
      : <LandingPage onGetStarted={() => setGetStarted(true)} />;
  }

  if (currentView === 'receipt' && activeReceipt) {
    return <WithdrawalReceipt receipt={activeReceipt} onBack={() => setCurrentView('dashboard')} />
  }

  return (
    <div className="min-h-screen bg-blue-50 dark:bg-gray-900 text-gray-800 dark:text-gray-200 transition-colors duration-300">
      <main className="w-full mx-auto p-4 sm:p-6 lg:p-8">
        <MobileDashboard
            assets={stockAssets}
            userProfile={userProfile}
            notifications={notifications}
            onWithdrawClick={() => setIsWithdrawModalOpen(true)}
            onProfileClick={() => setIsProfileModalOpen(true)}
            onLogout={handleLogout}
            theme={theme}
            onToggleTheme={toggleTheme}
            investmentStartTime={investmentStartTime}
        />
      </main>

      <div className="fixed bottom-4 left-4 w-full max-w-sm space-y-3 z-50">
        {notifications.slice(0, 3).map(notification => (
          <NotificationPopup key={notification.id} notification={notification} onRemove={removeNotification} />
        ))}
      </div>

      {modal.type === 'manageBalance' && modal.asset && (
        <ManageBalanceModal asset={modal.asset} onClose={() => setModal({ type: null, asset: null })} onUpdateBalance={handleUpdateBalance} />
      )}
      {modal.type === 'history' && modal.asset && (
        <TransactionHistoryModal asset={modal.asset} onClose={() => setModal({ type: null, asset: null })} />
      )}
      {modal.type === 'chart' && modal.asset && (
        <LiveChartModal asset={modal.asset} onClose={() => setModal({type: null, asset: null})} />
      )}
      {modal.type === 'alert' && modal.asset && (
        <PriceAlertModal asset={modal.asset} onClose={() => setModal({type: null, asset: null})} onAddAlert={handleAddAlert} onDeleteAlert={handleDeleteAlert} />
      )}
      {isWithdrawModalOpen && (
        <WithdrawModal totalValue={assets.reduce((acc, asset) => acc + asset.balance * asset.price, 0)} onClose={() => setIsWithdrawModalOpen(false)} onWithdraw={handleWithdraw} />
      )}
      {isProfileModalOpen && (
        <ProfileModal profile={userProfile} onClose={() => setIsProfileModalOpen(false)} onSave={handleSaveProfile} />
      )}
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { Receipt } from '../types';
import { ShieldCheckIcon, UserCircleIcon, ArrowDownTrayIcon } from './Icons';

interface WithdrawalReceiptProps {
  receipt: Receipt;
  onBack: () => void;
}

// Declare the htmlToImage library which is loaded from a script tag in index.html
declare const htmlToImage: any;

const WithdrawalReceipt: React.FC<WithdrawalReceiptProps> = ({ receipt, onBack }) => {
  const { userProfile } = receipt;
  const receiptRef = useRef<HTMLDivElement>(null);

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleString('en-GB', {
      dateStyle: 'long',
      timeStyle: 'short',
    });
  };

  const maskAccountNumber = (accountNumber: string) => {
    return `**** **** **** ${accountNumber.slice(-4)}`;
  };

  const handleDownload = async () => {
    if (receiptRef.current === null) {
      return;
    }

    try {
      const dataUrl = await htmlToImage.toPng(receiptRef.current, { 
        quality: 0.98,
        pixelRatio: 2, // Increase resolution for better quality
        style: {
          // Temporarily set a specific width during capture for consistency
          width: '672px', 
          margin: '0',
          borderRadius: '0',
        }
      });
      const link = document.createElement('a');
      link.download = `INVEST-EMPOWERMENT-Receipt-${receipt.transactionId}.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error('Oops, something went wrong!', err);
      alert('Failed to download receipt image. Please try again.');
    }
  };

  return (
    <div className="min-h-screen text-gray-800 dark:text-gray-200 transition-colors duration-300 p-4 sm:p-6 lg:p-8 flex flex-col items-center">
      <div className="w-full max-w-2xl">
        <div className="mb-6 flex flex-wrap justify-between items-center gap-4">
            <button onClick={onBack} className="text-emerald-600 dark:text-emerald-500 font-semibold hover:underline">
                &larr; Back to Dashboard
            </button>
            <button 
                onClick={handleDownload}
                className="flex items-center justify-center gap-2 bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-2 px-4 rounded-lg transition-colors duration-200 shadow-sm"
            >
                <ArrowDownTrayIcon className="w-5 h-5" />
                <span>Download Receipt</span>
            </button>
        </div>

        <div ref={receiptRef} className="bg-white dark:bg-gray-800 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 overflow-hidden">
          <div className="p-8 text-center bg-blue-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-700">
            <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Withdrawal Successful</h1>
            <p className="text-gray-500 dark:text-gray-400 mt-1">Your transaction has been completed successfully.</p>
            <div className="mt-4 inline-flex items-center gap-2 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-800 dark:text-emerald-300 font-medium py-1 px-3 rounded-full text-sm">
              <ShieldCheckIcon className="w-4 h-4" />
              <span>{receipt.status}</span>
            </div>
          </div>

          <div className="p-8 space-y-6">
            <div className="flex items-center gap-4">
              {userProfile.profilePicture ? (
                <img src={userProfile.profilePicture} alt="Profile" className="w-12 h-12 rounded-full object-cover" />
              ) : (
                <UserCircleIcon className="w-12 h-12 text-gray-400 dark:text-gray-500" />
              )}
              <div>
                <p className="font-bold text-gray-900 dark:text-white">{userProfile.fullName}</p>
                <p className="text-sm text-gray-500 dark:text-gray-400">{userProfile.email}</p>
              </div>
            </div>

            <div className="border-t border-gray-200 dark:border-gray-700 pt-6">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 text-center sm:text-left">
                <div>
                  <p className="text-sm text-gray-500 dark:text-gray-400">Amount Withdrawn</p>
                  <p className="text-xl font-bold text-gray-900 dark:text-white">
                    {receipt.amountGBP.toLocaleString('en-GB', { style: 'currency', currency: 'GBP' })}
                  </p>
                </div>
                <div className="sm:text-right">
                  <p className="text-sm text-gray-500 dark:text-gray-400">You Will Receive (Approx.)</p>
                  <p className="text-2xl font-extrabold text-emerald-600 dark:text-emerald-500">
                     {receipt.amountLocal.toLocaleString('en-US', { style: 'currency', currency: receipt.currency })}
                  </p>
                </div>
              </div>
            </div>

            {/* Bank Details Section */}
            <div className="border-t border-gray-200 dark:border-gray-700 pt-6">
                <h3 className="font-semibold text-lg mb-3 text-gray-800 dark:text-gray-200">Withdrawal Destination</h3>
                <div className="bg-blue-50 dark:bg-gray-700/50 rounded-lg p-4">
                     <ul className="space-y-2 text-sm">
                        <li className="flex justify-between">
                            <span className="text-gray-500 dark:text-gray-400">Bank Name</span>
                            <span className="font-medium text-gray-700 dark:text-gray-300">{receipt.bankName}</span>
                        </li>
                        <li className="flex justify-between">
                            <span className="text-gray-500 dark:text-gray-400">Account Holder</span>
                            <span className="font-medium text-gray-700 dark:text-gray-300">{receipt.accountHolderName}</span>
                        </li>
                        <li className="flex justify-between">
                            <span className="text-gray-500 dark:text-gray-400">Account Number</span>
                            <span className="font-mono text-gray-700 dark:text-gray-300">{maskAccountNumber(receipt.accountNumber)}</span>
                        </li>
                     </ul>
                </div>
            </div>

            <div className="bg-blue-50 dark:bg-gray-700/50 rounded-lg p-4">
              <h3 className="font-semibold text-lg mb-3 text-gray-800 dark:text-gray-200">Transaction Details</h3>
              <ul className="space-y-2 text-sm">
                <li className="flex justify-between">
                  <span className="text-gray-500 dark:text-gray-400">Transaction ID</span>
                  <span className="font-mono text-gray-700 dark:text-gray-300">{receipt.transactionId}</span>
                </li>
                <li className="flex justify-between">
                  <span className="text-gray-500 dark:text-gray-400">Status</span>
                  <span className="font-bold text-emerald-600 dark:text-emerald-500">{receipt.status}</span>
                </li>
                <li className="flex justify-between">
                  <span className="text-gray-500 dark:text-gray-400">Date & Time</span>
                  <span className="text-gray-700 dark:text-gray-300">{formatDate(receipt.date)}</span>
                </li>
                 <li className="flex justify-between">
                  <span className="text-gray-500 dark:text-gray-400">Exchange Rate</span>
                  <span className="text-gray-700 dark:text-gray-300">1 GBP ≈ {receipt.exchangeRate.toLocaleString()} {receipt.currency}</span>
                </li>
              </ul>
            </div>
          </div>

          <div className="p-4 text-center bg-blue-50 dark:bg-gray-800/50 border-t border-gray-200 dark:border-gray-700">
             <p className="text-xs text-gray-500 dark:text-gray-400">If you have any questions, please contact support.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WithdrawalReceipt;

import React from 'react';

// FIX: Removed circular self-import of UserProfile to resolve the 'Import declaration conflicts with local declaration' error.

export enum TransactionType {
  ADD = 'ADD',
  REMOVE = 'REMOVE',
  WITHDRAW = 'WITHDRAW',
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  date: string;
  description?: string;
}

export interface PriceAlert {
  id: string;
  type: 'above' | 'below';
  targetPrice: number;
  status: 'active' | 'triggered';
  createdAt: string;
}

export interface Asset {
  id: string;
  name: string;
  ticker: string;
  balance: number;
  price: number;
  logoUrl?: string;
  transactions: Transaction[];
  priceAlerts: PriceAlert[];
}

export interface UserProfile {
  fullName: string;
  email: string;
  bio: string;
  profilePicture: string | null;
}

export type Theme = 'light' | 'dark';

export interface Receipt {
  transactionId: string;
  date: string;
  status: 'Payment Successful' | 'Completed' | 'Failed';
  userProfile: UserProfile;
  amountUSD: number;
  amountLocal: number;
  currency: string;
  exchangeRate: number;
  bankName: string;
  accountHolderName: string;
  accountNumber: string;
}

export interface Notification {
  id: string;
  type: 'investors' | 'investment' | 'withdrawal' | 'price_alert' | 'new_member';
  icon: React.ElementType;
  title: string;
  message: string;
  timestamp: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { Asset, TransactionType, UserProfile, Notification, Receipt, PriceAlert } from './types';
import LandingPage from './components/LandingPage';
import LoginScreen from './components/LoginScreen';
import ManageBalanceModal from './components/ManageBalanceModal';
import TransactionHistoryModal from './components/TransactionHistoryModal';
import { initialAssets as newInitialAssets, initialProfile as newInitialProfile } from './mockData';
import LiveChartModal from './components/LiveChartModal';
import PriceAlertModal from './components/PriceAlertModal';
import { BanknotesIcon, BellAlertIcon, ChartBarIcon, UserPlusIcon } from './components/Icons';
import NotificationPopup from './components/NotificationPopup';
import WithdrawModal from './components/WithdrawModal';
import WithdrawalReceipt from './components/WithdrawalReceipt';
import ProfileModal from './components/ProfileModal';
import MobileDashboard from './components/MobileDashboard';

type ModalState = {
  type: 'manageBalance' | 'history' | 'chart' | 'alert' | null;
  asset: Asset | null;
};

// --- User Data Management ---
const USERS_DB_KEY = 'invest_empowerment_users';
const ACTIVE_USER_KEY = 'invest_empowerment_active_user';

const MOCK_INVESTORS = [
    { name: 'Mary T.', location: 'Port Moresby, Papua New Guinea' },
    { name: 'Ratu S.', location: 'Suva, Fiji' },
    { name: 'David K.', location: 'Lae, Papua New Guinea' },
    { name: 'Grace V.', location: 'Honiara, Solomon Islands' },
    { name: 'John P.', location: 'Mount Hagen, Papua New Guinea' },
    { name: 'Sarah L.', location: 'Goroka, Papua New Guinea' },
    { name: 'Tui F.', location: 'Apia, Samoa' },
    { name: 'Lina M.', location: 'Nukuʻalofa, Tonga' },
    { name: 'Ben G.', location: 'Port Vila, Vanuatu' },
    { name: 'Anna P.', location: 'Madang, Papua New Guinea' },
    { name: 'Samuel J.', location: 'Lautoka, Fiji' },
    { name: 'Jessica W.', location: 'Auki, Solomon Islands' },
];

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [getStarted, setGetStarted] = useState(false);
  const [loginError, setLoginError] = useState('');

  // State for the currently logged-in user
  const [activeUserEmail, setActiveUserEmail] = useState<string | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [investmentStartTime, setInvestmentStartTime] = useState<number | null>(null);

  const [modal, setModal] = useState<ModalState>({ type: null, asset: null });
  const [isWithdrawModalOpen, setIsWithdrawModalOpen] = useState(false);
  const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [currentView, setCurrentView] = useState<'dashboard' | 'receipt'>('dashboard');
  const [activeReceipt, setActiveReceipt] = useState<Receipt | null>(null);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return 'dark';
    }
    return 'light';
  });

  useEffect(() => {
    // Auto-login check on initial load
    const loggedInUserEmail = localStorage.getItem(ACTIVE_USER_KEY);
    if (loggedInUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const userData = users[loggedInUserEmail];
      if (userData) {
        setActiveUserEmail(loggedInUserEmail);
        setAssets(userData.assets);
        setUserProfile(userData.profile);
        setInvestmentStartTime(userData.investmentStartTime);
        setIsLoggedIn(true);
      }
    }
  }, []);

  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  const toggleTheme = () => {
    setTheme(prevTheme => prevTheme === 'light' ? 'dark' : 'light');
  };

  const saveUserData = (email: string, data: any) => {
    const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
    users[email] = data;
    localStorage.setItem(USERS_DB_KEY, JSON.stringify(users));
  };

  const addNotification = (notification: Omit<Notification, 'id' | 'timestamp'>) => {
    const newNotification: Notification = {
      ...notification,
      id: Date.now().toString() + Math.random(),
      timestamp: new Date().toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' }),
    };
    setNotifications(prev => [newNotification, ...prev]);
  };

  const removeNotification = (id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id));
  };

  useEffect(() => {
    if (!isLoggedIn) return;
    const activityInterval = setInterval(() => {
      if (notifications.length >= 5) return;
      const randomInvestor = MOCK_INVESTORS[Math.floor(Math.random() * MOCK_INVESTORS.length)];
      const randomAction = Math.random();
      let notificationData: Omit<Notification, 'id' | 'timestamp'>;
      if (randomAction < 0.5) {
        const amount = Math.floor(Math.random() * (5000 - 100 + 1) + 100);
        notificationData = { type: 'investment', icon: ChartBarIcon, title: 'New Investment', message: `${randomInvestor.name} from ${randomInvestor.location} has invested $${amount.toLocaleString()}.` };
      } else if (randomAction < 0.8) {
        const amount = Math.floor(Math.random() * (2000 - 200 + 1) + 200);
        notificationData = { type: 'withdrawal', icon: BanknotesIcon, title: 'Profit Withdrawal', message: `${randomInvestor.name} from ${randomInvestor.location} withdrew $${amount.toLocaleString()}.` };
      } else {
        notificationData = { type: 'new_member', icon: UserPlusIcon, title: 'Welcome!', message: `${randomInvestor.name} from ${randomInvestor.location} has just joined!` };
      }
      addNotification(notificationData);
    }, 4000);
    return () => clearInterval(activityInterval);
  }, [isLoggedIn, notifications]);

  const handleLogin = (email: string, password: string): boolean => {
    setLoginError('');
    const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
    const userData = users[email.toLowerCase()];

    if (userData && userData.password === password) {
      setActiveUserEmail(email.toLowerCase());
      setAssets(userData.assets);
      setUserProfile(userData.profile);
      setInvestmentStartTime(userData.investmentStartTime);
      setIsLoggedIn(true);
      localStorage.setItem(ACTIVE_USER_KEY, email.toLowerCase());
      addNotification({ type: 'new_member', icon: UserPlusIcon, title: 'Welcome back', message: 'You are now signed in to your dashboard.' });
      return true;
    }
    setLoginError('Invalid email or password.');
    return false;
  };

  const handleSignup = (email: string, password: string): boolean => {
    setLoginError('');
    const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
    const lowerCaseEmail = email.toLowerCase();

    if (users[lowerCaseEmail]) {
      setLoginError('An account with this email already exists.');
      return false;
    }

    const startTime = Date.now();
    const newUserProfile = { ...newInitialProfile, email: lowerCaseEmail, fullName: 'New Investor' };
    const newUserData = {
      password,
      profile: newUserProfile,
      assets: newInitialAssets,
      investmentStartTime: startTime,
    };

    saveUserData(lowerCaseEmail, newUserData);

    setActiveUserEmail(lowerCaseEmail);
    setAssets(newInitialAssets);
    setUserProfile(newUserProfile);
    setInvestmentStartTime(startTime);
    setIsLoggedIn(true);
    localStorage.setItem(ACTIVE_USER_KEY, lowerCaseEmail);
    addNotification({ type: 'new_member', icon: UserPlusIcon, title: 'Account Created!', message: 'Welcome to INVEST EMPOWERMENT!' });
    return true;
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setGetStarted(false);
    setActiveUserEmail(null);
    setAssets([]);
    setUserProfile(null);
    localStorage.removeItem(ACTIVE_USER_KEY);
  };

  const handleUpdateBalance = (assetId: string, amount: number, type: TransactionType, description?: string) => {
    const updatedAssets = assets.map(asset => {
      if (asset.id === assetId) {
        const newBalance = type === TransactionType.ADD ? asset.balance + amount : asset.balance - amount;
        const newTransaction = { id: `tx-${Date.now()}`, type, amount, date: new Date().toISOString(), description };
        addNotification({ type: 'investment', icon: ChartBarIcon, title: `Balance Updated for ${asset.ticker}`, message: `Successfully ${type === TransactionType.ADD ? 'added' : 'removed'} ${amount} ${asset.ticker}.` });
        return { ...asset, balance: newBalance, transactions: [...asset.transactions, newTransaction] };
      }
      return asset;
    });
    setAssets(updatedAssets);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }
  };

  const handleWithdraw = (details: { amount: number; convertedAmount: number; currency: string; rate: number; bankName: string; accountHolderName: string; accountNumber: string; }) => {
    if (!userProfile) return;
    const newReceipt: Receipt = {
      transactionId: `WD-${Date.now()}`, 
      date: new Date().toISOString(), 
      status: 'Payment Successful', 
      userProfile,
      amountUSD: details.amount, 
      amountLocal: details.convertedAmount, 
      currency: details.currency,
      exchangeRate: details.rate, 
      bankName: details.bankName, 
      accountHolderName: details.accountHolderName,
      accountNumber: details.accountNumber,
    };

    let remainingWithdrawal = details.amount;
    const updatedAssets = assets.map(asset => {
      const assetValue = asset.balance * asset.price;
      if (remainingWithdrawal > 0 && assetValue > 0) {
        const withdrawalFromAsset = Math.min(remainingWithdrawal, assetValue);
        const balanceToRemove = withdrawalFromAsset / asset.price;
        remainingWithdrawal -= withdrawalFromAsset;
        return { ...asset, balance: asset.balance - balanceToRemove };
      }
      return asset;
    }).filter(asset => asset.balance > 0.00001);

    setAssets(updatedAssets);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }

    addNotification({ type: 'withdrawal', icon: BanknotesIcon, title: 'Withdrawal Successful', message: `Your withdrawal of ${details.amount.toLocaleString('en-US', {style: 'currency', currency: 'USD'})} has been processed.` });
    setActiveReceipt(newReceipt);
    setCurrentView('receipt');
    setIsWithdrawModalOpen(false);
  };

  const handleAddAlert = (assetId: string, alert: Omit<PriceAlert, 'id' | 'status' | 'createdAt'>) => {
    const updatedAssets = assets.map(asset => {
      if (asset.id === assetId) {
        const newAlert: PriceAlert = { ...alert, id: `alert-${Date.now()}`, status: 'active' as const, createdAt: new Date().toISOString() };
        addNotification({ type: 'price_alert', icon: BellAlertIcon, title: 'Price Alert Set', message: `Alert for ${asset.ticker} when price is ${alert.type} ${alert.targetPrice.toLocaleString('en-US', {style: 'currency', currency: 'USD'})}.` });
        return { ...asset, priceAlerts: [...asset.priceAlerts, newAlert] };
      }
      return asset;
    });
    setAssets(updatedAssets);
     if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }
  };

  const handleDeleteAlert = (assetId: string, alertId: string) => {
    const updatedAssets = assets.map(asset => {
      if (asset.id === assetId) {
        return { ...asset, priceAlerts: asset.priceAlerts.filter(a => a.id !== alertId) };
      }
      return asset;
    });
    setAssets(updatedAssets);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, assets: updatedAssets });
    }
  };

  const handleSaveProfile = (updatedProfile: UserProfile) => {
    setUserProfile(updatedProfile);
    if (activeUserEmail) {
      const users = JSON.parse(localStorage.getItem(USERS_DB_KEY) || '{}');
      const currentUserData = users[activeUserEmail];
      saveUserData(activeUserEmail, { ...currentUserData, profile: updatedProfile });
    }
    addNotification({ type: 'new_member', icon: UserPlusIcon, title: 'Profile Updated', message: 'Your profile information has been saved successfully.' });
  };

  const stockAssets = useMemo(() => assets.filter(asset => asset.ticker !== 'BTC' && asset.ticker !== 'USD'), [assets]);

  if (!isLoggedIn || !userProfile) {
    return getStarted 
      ? <LoginScreen onLogin={handleLogin} onSignup={handleSignup} error={loginError} />
      : <LandingPage onGetStarted={() => setGetStarted(true)} />;
  }

  if (currentView === 'receipt' && activeReceipt) {
    return <WithdrawalReceipt receipt={activeReceipt} onBack={() => setCurrentView('dashboard')} />
  }

  return (
    <div className="min-h-screen bg-blue-50 dark:bg-gray-900 text-gray-800 dark:text-gray-200 transition-colors duration-300">
      <main className="w-full mx-auto p-4 sm:p-6 lg:p-8">
        <MobileDashboard
            assets={stockAssets}
            userProfile={userProfile}
            notifications={notifications}
            onWithdrawClick={() => setIsWithdrawModalOpen(true)}
            onProfileClick={() => setIsProfileModalOpen(true)}
            onLogout={handleLogout}
            theme={theme}
            onToggleTheme={toggleTheme}
            investmentStartTime={investmentStartTime}
        />
      </main>

      <div className="fixed bottom-4 left-4 w-full max-w-sm space-y-3 z-50">
        {notifications.slice(0, 3).map(notification => (
          <NotificationPopup key={notification.id} notification={notification} onRemove={removeNotification} />
        ))}
      </div>

      {modal.type === 'manageBalance' && modal.asset && (
        <ManageBalanceModal asset={modal.asset} onClose={() => setModal({ type: null, asset: null })} onUpdateBalance={handleUpdateBalance} />
      )}
      {modal.type === 'history' && modal.asset && (
        <TransactionHistoryModal asset={modal.asset} onClose={() => setModal({ type: null, asset: null })} />
      )}
      {modal.type === 'chart' && modal.asset && (
        <LiveChartModal asset={modal.asset} onClose={() => setModal({type: null, asset: null})} />
      )}
      {modal.type === 'alert' && modal.asset && (
        <PriceAlertModal asset={modal.asset} onClose={() => setModal({type: null, asset: null})} onAddAlert={handleAddAlert} onDeleteAlert={handleDeleteAlert} />
      )}
      {isWithdrawModalOpen && (
        <WithdrawModal totalValue={assets.reduce((acc, asset) => acc + asset.balance * asset.price, 0)} onClose={() => setIsWithdrawModalOpen(false)} onWithdraw={handleWithdraw} />
      )}
      {isProfileModalOpen && (
        <ProfileModal profile={userProfile} onClose={() => setIsProfileModalOpen(false)} onSave={handleSaveProfile} />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Asset } from '../types';
import AssetLogo from './AssetLogo';
import TradingChartPreview from './TradingChartPreview';
import { ListBulletIcon, ChartPieIcon, BellAlertIcon, BitcoinIcon } from './Icons';

interface AssetRowProps {
  asset: Asset;
  totalPortfolioValue: number;
  onManageBalance: (asset: Asset) => void;
  onViewHistory: (asset: Asset) => void;
  onViewChart: (asset: Asset) => void;
  onSetAlert: (asset: Asset) => void;
}

const AssetRow: React.FC<AssetRowProps> = ({ asset, totalPortfolioValue, onManageBalance, onViewHistory, onViewChart, onSetAlert }) => {
  const value = asset.balance * asset.price;
  const allocation = totalPortfolioValue > 0 ? (value / totalPortfolioValue) * 100 : 0;

  return (
    <tr className="border-b border-gray-200 dark:border-gray-700 hover:bg-gray-100/50 dark:hover:bg-gray-700/50 transition-colors duration-200">
      <td className="p-4">
        <div className="flex items-center gap-4">
          <AssetLogo asset={asset} />
          <div>
            <p className="font-bold text-gray-900 dark:text-white">{asset.name}</p>
            {asset.ticker === 'BTC' ? (
              <div className="flex items-center gap-1.5 text-sm text-gray-500 dark:text-gray-400">
                <BitcoinIcon className="w-4 h-4 text-orange-500" />
                <span>{asset.ticker}</span>
              </div>
            ) : (
              <p className="text-sm text-gray-500 dark:text-gray-400">{asset.ticker}</p>
            )}
          </div>
        </div>
      </td>
      <td className="p-4 text-right">
        <p className="font-medium text-gray-800 dark:text-gray-300">{asset.price.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}</p>
      </td>
      <td className="p-4 text-right">
        <p className="font-medium text-gray-800 dark:text-gray-300">{asset.balance.toLocaleString()} {asset.ticker}</p>
        <p className="text-sm text-gray-500 dark:text-gray-400">{value.toLocaleString('en-US', { style: 'currency', currency: 'USD' })}</p>
      </td>
      <td className="p-4 hidden lg:table-cell">
        <TradingChartPreview />
      </td>
      <td className="p-4 text-right hidden md:table-cell">
        <div className="flex flex-col items-end">
          <p className="font-medium text-gray-800 dark:text-gray-300">{allocation.toFixed(2)}%</p>
          <div className="w-24 bg-gray-200 dark:bg-gray-600 rounded-full h-1.5 mt-1">
            <div className="bg-emerald-500 h-1.5 rounded-full" style={{ width: `${Math.max(0, allocation)}%` }}></div>
          </div>
        </div>
      </td>
      <td className="p-4 text-right">
        <div className="flex justify-end items-center gap-2">
            <button 
                onClick={() => onSetAlert(asset)}
                className="bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 font-bold p-2 rounded-lg transition-colors duration-200"
                aria-label="Set price alert"
            >
                <BellAlertIcon className="w-5 h-5" />
            </button>
            <button 
                onClick={() => onViewChart(asset)}
                className="bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 font-bold p-2 rounded-lg transition-colors duration-200"
                aria-label="View live chart"
            >
                <ChartPieIcon className="w-5 h-5" />
            </button>
            <button 
                onClick={() => onViewHistory(asset)}
                className="bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 font-bold p-2 rounded-lg transition-colors duration-200"
                aria-label="View history"
            >
                <ListBulletIcon className="w-5 h-5" />
            </button>
            <button 
                onClick={() => onManageBalance(asset)} 
                className="bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-2 px-4 rounded-lg transition-colors duration-200 text-sm"
            >
                Manage
            </button>
        </div>
      </td>
    </tr>
  );
};

export default AssetRow;

import React, { useState, FormEvent } from 'react';
import { Asset, TransactionType } from '../types';
import { XMarkIcon, PlusIcon, MinusIcon } from './Icons';
import AssetLogo from './AssetLogo';

interface ManageBalanceModalProps {
  asset: Asset;
  onClose: () => void;
  onUpdateBalance: (assetId: string, amount: number, type: TransactionType, description?: string) => void;
}

const ManageBalanceModal: React.FC<ManageBalanceModalProps> = ({ asset, onClose, onUpdateBalance }) => {
  const [amount, setAmount] = useState<number | string>('');
  const [description, setDescription] = useState('');
  const [transactionType, setTransactionType] = useState<TransactionType>(TransactionType.ADD);
  const [error, setError] = useState('');
  const [view, setView] = useState<'main' | 'confirmCode'>('main');
  const [secretCode, setSecretCode] = useState('');

  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setError('');
    const value = e.target.value;
    if (value === '' || /^\d*\.?\d*$/.test(value)) {
      setAmount(value);
    }
  };

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    setError('');
    const numericAmount = parseFloat(amount as string);

    if (isNaN(numericAmount) || numericAmount <= 0) {
      setError('Please enter a valid, positive amount.');
      return;
    }

    if (transactionType === TransactionType.REMOVE) {
      if (numericAmount > asset.balance) {
        setError(`Cannot remove more than the current balance of ${asset.balance.toLocaleString()} ${asset.ticker}.`);
        return;
      }
      onUpdateBalance(asset.id, numericAmount, transactionType, description);
      onClose();
    } else { // It's an ADD transaction, so ask for secret code
      setView('confirmCode');
    }
  };

  const handleConfirmAdd = (e: FormEvent) => {
    e.preventDefault();
    if (secretCode.toLowerCase() !== 'funds') {
      setError('Invalid secret code. Please try again.');
      return;
    }
    const numericAmount = parseFloat(amount as string);
    onUpdateBalance(asset.id, numericAmount, TransactionType.ADD, description);
    onClose();
  };

  const handleBackToMain = () => {
    setError('');
    setSecretCode('');
    setView('main');
  };

  const value = asset.balance * asset.price;

  return (
    <div className="fixed inset-0 bg-black bg-opacity-70 flex justify-center items-center z-50 p-4">
      <div className="bg-white dark:bg-gray-800 rounded-2xl shadow-2xl w-full max-w-md border border-gray-200 dark:border-gray-700">
        <div className="flex justify-between items-center p-6 border-b border-gray-200 dark:border-gray-700">
          <h2 className="text-xl font-bold text-gray-900 dark:text-white">
            {view === 'main' ? `Manage ${asset.name} Balance` : 'Authorization Required'}
          </h2>
          <button onClick={onClose} className="text-gray-400 hover:text-gray-700 dark:hover:text-gray-300 transition-colors">
            <XMarkIcon className="w-7 h-7" />
          </button>
        </div>

        {view === 'main' ? (
          <form onSubmit={handleSubmit}>
            <div className="p-6">
              <div className="flex items-center gap-4 mb-6">
                <AssetLogo asset={asset} size="lg" />
                <div>
                  <p className="font-bold text-gray-900 dark:text-white text-lg">{asset.name} ({asset.ticker})</p>
                  <p className="text-sm text-gray-500 dark:text-gray-400">
                    Current Balance: {asset.balance.toLocaleString()} {asset.ticker} ({value.toLocaleString('en-US', { style: 'currency', currency: 'USD' })})
                  </p>
                </div>
              </div>

              <div className="mb-4">
                <label htmlFor="amount" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Amount in {asset.ticker}
                </label>
                <input
                  id="amount"
                  type="text"
                  value={amount}
                  onChange={handleAmountChange}
                  placeholder="e.g., 0.5"
                  required
                  className="w-full bg-white dark:bg-gray-900/50 border border-gray-300 dark:border-gray-600 rounded-lg px-4 py-3 text-gray-900 dark:text-white focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
                />
              </div>

              <div className="mb-6">
                <label htmlFor="description" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                    Description (Optional)
                </label>
                <input
                    id="description"
                    type="text"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="e.g., Monthly savings"
                    maxLength={50}
                    className="w-full bg-white dark:bg-gray-900/50 border border-gray-300 dark:border-gray-600 rounded-lg px-4 py-3 text-gray-900 dark:text-white focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
                />
              </div>

              {error && <p className="text-red-500 text-sm mb-4">{error}</p>}

              <div className="grid grid-cols-2 gap-4">
                  <button
                      type="submit"
                      onClick={() => setTransactionType(TransactionType.ADD)}
                      className="flex items-center justify-center gap-2 w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3 px-4 rounded-lg transition-colors duration-200 shadow-sm"
                  >
                      <PlusIcon className="w-5 h-5" />
                      <span>Add to Balance</span>
                  </button>
                  <button
                      type="submit"
                      onClick={() => setTransactionType(TransactionType.REMOVE)}
                      className="flex items-center justify-center gap-2 w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 px-4 rounded-lg transition-colors duration-200 shadow-sm"
                  >
                      <MinusIcon className="w-5 h-5" />
                      <span>Remove from Balance</span>
                  </button>
              </div>
            </div>

            <div className="bg-blue-50 dark:bg-gray-800/50 p-4 rounded-b-2xl flex justify-end">
               <button type="button" onClick={onClose} className="bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 font-bold py-2 px-6 rounded-lg transition-colors">
                Cancel
              </button>
            </div>
          </form>
        ) : ( // view === 'confirmCode'
          <form onSubmit={handleConfirmAdd}>
            <div className="p-6">
              <p className="text-center text-gray-700 dark:text-gray-300 mb-4">
                A secret code is required to add funds to your investment.
              </p>
              <div className="mb-4">
                <label htmlFor="secretCode" className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
                  Secret Code
                </label>
                <input
                  id="secretCode"
                  type="password"
                  value={secretCode}
                  onChange={(e) => {
                    setSecretCode(e.target.value);
                    setError('');
                  }}
                  placeholder="Enter authorization code"
                  required
                  autoFocus
                  className="w-full bg-white dark:bg-gray-900/50 border border-gray-300 dark:border-gray-600 rounded-lg px-4 py-3 text-gray-900 dark:text-white focus:ring-2 focus:ring-emerald-500 focus:border-emerald-500 outline-none"
                />
              </div>
              {error && <p className="text-red-500 text-sm mb-4 text-center">{error}</p>}
            </div>
            <div className="bg-blue-50 dark:bg-gray-800/50 p-4 rounded-b-2xl flex justify-end gap-4">
              <button type="button" onClick={handleBackToMain} className="bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 font-bold py-2 px-6 rounded-lg transition-colors">
                Back
              </button>
              <button
                type="submit"
                className="flex items-center justify-center gap-2 w-auto bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-2 px-6 rounded-lg transition-colors duration-200 shadow-sm"
              >
                Authorize & Add
              </button>
            </div>
          </form>
        )}
      </div>
    </div>
  );
};

