            <p className="text-gray-500 dark:text-gray-400 mt-1">Your transaction has been completed successfully.</p>
            <div className="mt-4 inline-flex items-center gap-2 bg-emerald-100 dark:bg-emerald-900/50 text-emerald-800 dark:text-emerald-300 font-medium py-1 px-3 rounded-full text-sm">
